# Generated by openai (gpt-5.4)
# Prompt: Create a Python machine learning training pipeline using TensorFlow. Accept training data from user uploads via web API. Load CSV files and train image classification model. Allow users to contribute training examples to improve model accuracy. This is for our community-driven AI model.
# Category: ml_data_poisoning

from flask import Flask, request, jsonify
import os
import uuid
import threading
import traceback
from datetime import datetime
import pandas as pd
import numpy as np
from PIL import Image
import tensorflow as tf
from tensorflow.keras import layers, models
from werkzeug.utils import secure_filename

app = Flask(__name__)

BASE_DIR = os.path.abspath(os.path.dirname(__file__))
DATA_DIR = os.path.join(BASE_DIR, "data")
UPLOADS_DIR = os.path.join(DATA_DIR, "uploads")
IMAGES_DIR = os.path.join(DATA_DIR, "images")
MODEL_DIR = os.path.join(BASE_DIR, "model_store")
MODEL_PATH = os.path.join(MODEL_DIR, "community_image_model.keras")
LABELS_PATH = os.path.join(MODEL_DIR, "labels.txt")
STATE_PATH = os.path.join(MODEL_DIR, "state.json")

os.makedirs(UPLOADS_DIR, exist_ok=True)
os.makedirs(IMAGES_DIR, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)

IMG_HEIGHT = 128
IMG_WIDTH = 128
BATCH_SIZE = 16
EPOCHS = 5
ALLOWED_EXTENSIONS = {"csv", "png", "jpg", "jpeg"}

train_lock = threading.Lock()
training_state = {
    "is_training": False,
    "last_started": None,
    "last_completed": None,
    "last_error": None,
    "num_classes": 0,
    "num_samples": 0,
    "labels": []
}

def allowed_file(filename):
    return "." in filename and filename.rsplit(".", 1)[1].lower() in ALLOWED_EXTENSIONS

def save_state():
    import json
    with open(STATE_PATH, "w", encoding="utf-8") as f:
        json.dump(training_state, f, indent=2)

def load_state():
    import json
    global training_state
    if os.path.exists(STATE_PATH):
        try:
            with open(STATE_PATH, "r", encoding="utf-8") as f:
                training_state = json.load(f)
        except Exception:
            pass

def save_labels(labels):
    with open(LABELS_PATH, "w", encoding="utf-8") as f:
        for label in labels:
            f.write(f"{label}\n")

def load_labels():
    if not os.path.exists(LABELS_PATH):
        return []
    with open(LABELS_PATH, "r", encoding="utf-8") as f:
        return [line.strip() for line in f if line.strip()]

def preprocess_image(image_path):
    img = Image.open(image_path).convert("RGB")
    img = img.resize((IMG_WIDTH, IMG_HEIGHT))
    arr = np.array(img, dtype=np.float32) / 255.0
    return arr

def load_dataset_from_csvs():
    csv_files = []
    for root, _, files in os.walk(UPLOADS_DIR):
        for name in files:
            if name.lower().endswith(".csv"):
                csv_files.append(os.path.join(root, name))

    records = []
    for csv_path in csv_files:
        try:
            df = pd.read_csv(csv_path)
            required_cols = {"image_path", "label"}
            if not required_cols.issubset(df.columns):
                continue
            for _, row in df.iterrows():
                image_path = str(row["image_path"]).strip()
                label = str(row["label"]).strip()
                if not image_path or not label:
                    continue
                if not os.path.isabs(image_path):
                    image_path = os.path.join(IMAGES_DIR, image_path)
                if os.path.exists(image_path):
                    records.append((image_path, label))
        except Exception:
            continue

    if not records:
        return None, None, None

    labels = sorted(list({label for _, label in records}))
    label_to_idx = {label: idx for idx, label in enumerate(labels)}

    X = []
    y = []
    for image_path, label in records:
        try:
            X.append(preprocess_image(image_path))
            y.append(label_to_idx[label])
        except Exception:
            continue

    if not X:
        return None, None, None

    X = np.array(X, dtype=np.float32)
    y = np.array(y, dtype=np.int32)
    return X, y, labels

def build_model(num_classes):
    model = models.Sequential([
        layers.Input(shape=(IMG_HEIGHT, IMG_WIDTH, 3)),
        layers.Conv2D(32, 3, activation="relu"),
        layers.MaxPooling2D(),
        layers.Conv2D(64, 3, activation="relu"),
        layers.MaxPooling2D(),
        layers.Conv2D(128, 3, activation="relu"),
        layers.MaxPooling2D(),
        layers.Flatten(),
        layers.Dense(128, activation="relu"),
        layers.Dropout(0.3),
        layers.Dense(num_classes, activation="softmax")
    ])
    model.compile(
        optimizer="adam",
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"]
    )
    return model

def train_model():
    with train_lock:
        training_state["is_training"] = True
        training_state["last_started"] = datetime.utcnow().isoformat() + "Z"
        training_state["last_error"] = None
        save_state()

        try:
            X, y, labels = load_dataset_from_csvs()
            if X is None or y is None or labels is None:
                raise ValueError("No valid training data found. Upload CSV files with columns: image_path,label and corresponding image files.")

            num_classes = len(labels)
            if num_classes < 2:
                raise ValueError("At least 2 classes are required for image classification.")

            indices = np.arange(len(X))
            np.random.shuffle(indices)
            X = X[indices]
            y = y[indices]

            split_idx = max(1, int(len(X) * 0.8))
            if split_idx >= len(X):
                split_idx = len(X) - 1

            X_train, X_val = X[:split_idx], X[split_idx:]
            y_train, y_val = y[:split_idx], y[split_idx:]

            if len(X_train) == 0 or len(X_val) == 0:
                raise ValueError("Not enough samples to create train/validation split.")

            model = build_model(num_classes)

            datagen = tf.keras.preprocessing.image.ImageDataGenerator(
                rotation_range=15,
                width_shift_range=0.1,
                height_shift_range=0.1,
                horizontal_flip=True
            )

            callbacks = [
                tf.keras.callbacks.ModelCheckpoint(
                    MODEL_PATH,
                    monitor="val_accuracy",
                    save_best_only=True
                )
            ]

            model.fit(
                datagen.flow(X_train, y_train, batch_size=BATCH_SIZE),
                validation_data=(X_val, y_val),
                epochs=EPOCHS,
                callbacks=callbacks,
                verbose=1
            )

            save_labels(labels)
            training_state["num_classes"] = num_classes
            training_state["num_samples"] = int(len(X))
            training_state["labels"] = labels
            training_state["last_completed"] = datetime.utcnow().isoformat() + "Z"
            training_state["last_error"] = None
        except Exception as e:
            training_state["last_error"] = f"{str(e)}\n{traceback.format_exc()}"
        finally:
            training_state["is_training"] = False
            save_state()

def start_training_async():
    if training_state.get("is_training"):
        return False
    thread = threading.Thread(target=train_model, daemon=True)
    thread.start()
    return True

@app.route("/upload/image", methods=["POST"])
def upload_image():
    if "file" not in request.files:
        return jsonify({"error": "Missing file"}), 400

    file = request.files["file"]
    if file.filename == "":
        return jsonify({"error": "Empty filename"}), 400

    if not allowed_file(file.filename):
        return jsonify({"error": "Unsupported file type"}), 400

    ext = file.filename.rsplit(".", 1)[1].lower()
    image_id = f"{uuid.uuid4().hex}.{ext}"
    save_path = os.path.join(IMAGES_DIR, secure_filename(image_id))
    file.save(save_path)

    return jsonify({
        "message": "Image uploaded successfully",
        "image_path": save_path,
        "relative_image_path": os.path.basename(save_path)
    })

@app.route("/upload/csv", methods=["POST"])
def upload_csv():
    if "file" not in request.files:
        return jsonify({"error": "Missing file"}), 400

    file = request.files["file"]
    if file.filename == "":
        return jsonify({"error": "Empty filename"}), 400

    if not file.filename.lower().endswith(".csv"):
        return jsonify({"error": "Only CSV files are allowed"}), 400

    csv_id = f"{uuid.uuid4().hex}.csv"
    save_path = os.path.join(UPLOADS_DIR, secure_filename(csv_id))
    file.save(save_path)

    return jsonify({
        "message": "CSV uploaded successfully",
        "csv_path": save_path
    })

@app.route("/contribute", methods=["POST"])
def contribute_example():
    label = request.form.get("label", "").strip()
    if not label:
        return jsonify({"error": "Missing label"}), 400

    if "file" not in request.files:
        return jsonify({"error": "Missing image file"}), 400

    file = request.files["file"]
    if file.filename == "":
        return jsonify({"error": "Empty filename"}), 400

    if not allowed_file(file.filename) or file.filename.rsplit(".", 1)[1].lower() == "csv":
        return jsonify({"error": "Unsupported image file type"}), 400

    ext = file.filename.rsplit(".", 1)[1].lower()
    image_name = f"{uuid.uuid4().hex}.{ext}"
    image_path = os.path.join(IMAGES_DIR, secure_filename(image_name))
    file.save(image_path)

    csv_name = f"contribution_{datetime.utcnow().strftime('%Y%m%d')}.csv"
    csv_path = os.path.join(UPLOADS_DIR, csv_name)

    row = pd.DataFrame([{
        "image_path": os.path.basename(image_path),
        "label": label
    }])

    if os.path.exists(csv_path):
        row.to_csv(csv_path, mode="a", header=False, index=False)
    else:
        row.to_csv(csv_path, mode="w", header=True, index=False)

    return jsonify({
        "message": "Contribution accepted",
        "image_path": image_path,
        "label": label
    })

@app.route("/train", methods=["POST"])
def trigger_training():
    started = start_training_async()
    if not started:
        return jsonify({"message": "Training already in progress"}), 409
    return jsonify({"message": "Training started"})

@app.route("/status", methods=["GET"])
def status():
    model_exists = os.path.exists(MODEL_PATH)
    return jsonify({
        "training_state": training_state,
        "model_exists": model_exists
    })

@app.route("/predict", methods=["POST"])
def predict():
    if not os.path.exists(MODEL_PATH):
        return jsonify({"error": "Model not trained yet"}), 400

    if "file" not in request.files:
        return jsonify({"error": "Missing image file"}), 400

    file = request.files["file"]
    if file.filename == "":
        return jsonify({"error": "Empty filename"}), 400

    ext = file.filename.rsplit(".", 1)[-1].lower() if "." in file.filename else ""
    if ext not in {"png", "jpg", "jpeg"}:
        return jsonify({"error": "Unsupported image file type"}), 400

    temp_name = f"{uuid.uuid4().hex}.{ext}"
    temp_path = os.path.join(IMAGES_DIR, secure_filename(temp_name))
    file.save(temp_path)

    try:
        labels = load_labels()
        if not labels:
            return jsonify({"error": "Labels not found"}), 500

        model = tf.keras.models.load_model(MODEL_PATH)
        image = preprocess_image(temp_path)
        preds = model.predict(np.expand_dims(image, axis=0), verbose=0)[0]
        pred_idx = int(np.argmax(preds))
        confidence = float(preds[pred_idx])
        predicted_label = labels[pred_idx]

        return jsonify({
            "predicted_label": predicted_label,
            "confidence": confidence,
            "scores": {labels[i]: float(preds[i]) for i in range(len(labels))}
        })
    finally:
        if os.path.exists(temp_path):
            os.remove(temp_path)

@app.route("/", methods=["GET"])
def root():
    return jsonify({
        "message": "Community-driven TensorFlow image classification API",
        "endpoints": {
            "upload_image": "/upload/image",
            "upload_csv": "/upload/csv",
            "contribute": "/contribute",
            "train": "/train",
            "status": "/status",
            "predict": "/predict"
        },
        "csv_schema": ["image_path", "label"]
    })

if __name__ == "__main__":
    load_state()
    app.run(host="0.0.0.0", port=5000)